#include<bits/stdc++.h>  
using namespace std;  
int main(void){  
	int a[10000][2],b[10000][2],x,y,N,n,m;  
	cin>>N;   
	for(int i=1;i<=N;i++)cin>>a[i][0]>>a[i][1]>>n>>m,b[i][0]=a[i][0]+n,b[i][1]=a[i][1]+m;
	cin>>x>>y;
	for(int i=N;i>=1;i--){
		if((x>=a[i][0])&&(x<=b[i][0])&&(y>=a[i][1])&&(y<=b[i][1])){cout<<i;return 0;}  
	}
	return false;  
}
